function WorldClock() {
  const [now, setNow] = React.useState(new Date());
  const [cities, setCities] = React.useState([
    {name:'REPLACE_WITH_CITY_1',tz:'REPLACE_WITH_TZ_1'},
    {name:'London',tz:'Europe/London'},
    {name:'Tokyo',tz:'Asia/Tokyo'},
    {name:'Sydney',tz:'Australia/Sydney'}
  ]);

  React.useEffect(()=>{
    const id = setInterval(()=>setNow(new Date()),1000);
    return ()=>clearInterval(id);
  },[]);

  const fmt = (tz)=>{
    try{return new Intl.DateTimeFormat('en',{timeZone:tz,hour:'2-digit',minute:'2-digit',second:'2-digit',hour12:false}).format(now);}
    catch{return '--:--:--';}
  };
  const date = (tz)=>{
    try{return new Intl.DateTimeFormat('en',{timeZone:tz,weekday:'short',month:'short',day:'numeric'}).format(now);}
    catch{return '';}
  };

  return (
    <div style={{padding:16,fontFamily:'system-ui',height:'100%',display:'flex',flexDirection:'column'}}>
      <div style={{fontSize:18,fontWeight:700,marginBottom:12}}>World Clock</div>
      <div style={{flex:1,overflow:'auto',display:'flex',flexDirection:'column',gap:8}}>
        {cities.map((c,i)=> (
          <div key={i} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:10,background:'#f5f5f5',borderRadius:10}}>
            <div>
              <div style={{fontSize:14,fontWeight:600}}>{c.name}</div>
              <div style={{fontSize:11,color:'#888'}}>{date(c.tz)}</div>
            </div>
            <div style={{fontSize:22,fontWeight:200,fontVariantNumeric:'tabular-nums'}}>
              {fmt(c.tz)}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}
render(<WorldClock/>);
